33	export function processScenario(scenario: Scenario): ScenarioOutput {
34	  const step = scenario.steps[0];
35	  if (step.items.length === 0) {
36	    return { results: [{ premium: PROCESSING_FEE }] };
37	  }
38	  const basePremium = BASE_PREMIUMS[step.items[0].type];
39	  const surcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
40	  const premium = basePremium + surcharge + PROCESSING_FEE;
41	  return { results: [{ premium }] };
42	}
